+// These words are clauses only in BigQuery pipe syntax. Keeping them as their
+// normal token types elsewhere preserves formatting of traditional statements.
+function promotePipeClauses(tokens: Token[]): Token[] {
+  let followsPipe = false;
+  return tokens.map(token => {
+    if (token.type === TokenType.PIPE) {
+      followsPipe = true;
+      return token;
+    }
+    if (token.type === TokenType.LINE_COMMENT || token.type === TokenType.BLOCK_COMMENT) {
+      return token;
+    }
+    if (followsPipe) {
+      followsPipe = false;
+      if (['AGGREGATE', 'EXTEND', 'SET', 'DROP', 'AS'].includes(token.text)) {
+        return { ...token, type: TokenType.RESERVED_CLAUSE };
+      }
+    }
+    return token;
+  });
